from typing import List

class Solution:
    def triangleType(self, nums: List[int]) -> str:
        # Sort the sides to simplify the triangle inequality checks
        nums.sort()

        # Check if the sides can form a triangle
        if nums[0] + nums[1] <= nums[2]:
            return "none"

        # Check the type of triangle
        if nums[0] == nums[1] == nums[2]:
            return "equilateral"
        elif nums[0] == nums[1] or nums[1] == nums[2]:
            return "isosceles"
        else:
            return "scalene"
```

This solution first sorts the sides of the triangle to simplify the triangle inequality check. It then checks if the given sides can form a triangle. If they can, it determines the type of triangle based on the equality of its sides.
